      "<config xmlns=\"urn:ietf:params:xml:ns:netconf:base:1.0\">\n  <native xmlns=\"http://cisco.com/ns/yang/Cisco-IOS-XE-native\"\n      xmlns:ios=\"http://cisco.com/ns/yang/Cisco-IOS-XE-native\">\n    <ip>\n      <access-list>\n        <extended xmlns=\"http://cisco.com/ns/yang/Cisco-IOS-XE-acl\"\n            xmlns:nc=\"urn:ietf:params:xml:ns:netconf:base:1.0\" nc:operation=\"replace\">\n          <name>netconf-operation-challenge-1</name>\n          <access-list-seq-rule>\n            <sequence>10</sequence>\n            <ace-rule>\n              <action>permit</action>\n              <protocol>tcp</protocol>\n              <any/>\n              <src-gt>100</src-gt>\n              <dest-ipv4-address>203.36.36.32</dest-ipv4-address>\n              <dest-mask>0.0.0.15</dest-mask>\n              <dst-eq>636</dst-eq>\n            </ace-rule>\n          </access-list-seq-rule>\n          <access-list-seq-rule>\n            <sequence>20</sequence>\n            <ace-rule>\n              <action>deny</action>\n              <protocol>ip</protocol>\n              <host-address>198.51.100.6</host-address>\n              <any/>\n            </ace-rule>\n          </access-list-seq-rule>\n        </extended>\n      </access-list>\n    </ip>\n  </native>\n</config>"
